import React, { useState, useEffect, useRef, useContext } from "react";
import { useParams, useNavigate } from "react-router-dom";
import io from "socket.io-client";
import {
  Button,
  TextField,
  Box,
  Paper,
  Typography,
  List,
  ListItem,
  ListItemText,
} from "@mui/material";
import { AuthContext } from "../contexts/AuthContext";

const ChatRoom = () => {
  const { isAuthenticated } = useContext(AuthContext);
  const { roomName } = useParams();
  const [socket, setSocket] = useState(null);
  const [messages, setMessages] = useState([]);
  const [inputMessage, setInputMessage] = useState("");
  const navigate = useNavigate();
  const messagesEndRef = useRef(null);

  useEffect(() => {
    if (!isAuthenticated) {
      navigate("/login");
      return;
    }

    const newSocket = io("http://localhost:3000");
    setSocket(newSocket);

    newSocket.emit("joinRoom", roomName);

    newSocket.on("message", (message) => {
      setMessages((prevMessages) => [...prevMessages, message]);
    });

    newSocket.on("recentMessages", (recentMessages) => {
      setMessages(recentMessages);
    });

    newSocket.on("userJoined", ({ user, message }) => {
      setMessages((prevMessages) => [...prevMessages, message]);
    });

    newSocket.on("userLeft", ({ user, message }) => {
      setMessages((prevMessages) => [...prevMessages, message]);
    });

    newSocket.emit("getRecentMessages", roomName);

    return () => {
      newSocket.emit("leaveRoom", roomName);
      newSocket.close();
    };
  }, [roomName, isAuthenticated, navigate]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const sendMessage = (e) => {
    e.preventDefault();
    if (inputMessage && socket) {
      socket.emit("sendMessage", { room: roomName, message: inputMessage });
      setInputMessage("");
    }
  };

  const leaveRoom = () => {
    if (socket) {
      socket.emit("leaveRoom", roomName);
      navigate("/");
    }
  };

  return (
    <Box sx={{ maxWidth: 600, margin: "auto", mt: 4 }}>
      {isAuthenticated ? (
        <Paper elevation={3} sx={{ p: 3 }}>
          <Typography variant="h5" gutterBottom>
            聊天室: {roomName}
          </Typography>
          <Button variant="outlined" onClick={leaveRoom} sx={{ mb: 2 }}>
            離開房間
          </Button>
          <Paper
            variant="outlined"
            sx={{ height: 300, overflow: "auto", mb: 2, p: 2 }}
          >
            <List>
              {messages.map((message, index) => (
                <ListItem key={index}>
                  <ListItemText
                    primary={message.text}
                    secondary={`${message.sender} - ${new Date(
                      message.timestamp
                    ).toLocaleString()}`}
                  />
                </ListItem>
              ))}
              <div ref={messagesEndRef} />
            </List>
          </Paper>
          <Box
            component="form"
            onSubmit={sendMessage}
            sx={{ display: "flex", gap: 1 }}
          >
            <TextField
              fullWidth
              value={inputMessage}
              onChange={(e) => setInputMessage(e.target.value)}
              placeholder="輸入消息"
              variant="outlined"
              size="small"
            />
            <Button type="submit" variant="contained">
              發送
            </Button>
          </Box>
        </Paper>
      ) : (
        <Typography variant="h6">請先登入以訪問聊天室</Typography>
      )}
    </Box>
  );
};

export default ChatRoom;
